SELECT pbe.Id as PricebookEntryId, pbe.Product2Id, pbe.UnitPrice as ListUnitPrice, p2.Name as ProductName
FROM PricebookEntry pbe
JOIN Product2 p2 ON p2.Id=pbe.Product2Id;

